/* 简约风格 */
.modern-form {
	padding: 10px 10px;
}

.modern-form .el-form-item {
	margin-bottom: 16px;
}

.modern-form .el-form-item__label {
	font-weight: 500;
	color: #606266;
	font-size: 14px;
}

.field-full {
	width: 100%;
}

.modern-dialog .el-select {
	width: 100%;
}

/* 固定对话框，禁止滚动 */
.fixed-dialog >>> .el-dialog {
	position: fixed;
	top: 50%;
	left: 50%;
	transform: translate(-50%, -50%);
	margin: 0 !important;
}

.fixed-dialog >>> .el-dialog__wrapper {
	overflow: hidden !important;
}

.fixed-dialog >>> .el-dialog__body {
	padding: 15px 20px;
	overflow: visible;
	max-height: none;
}

/* 图片上传样式 */
.avatar-uploader >>> .el-upload {
	border: 1px dashed #d9d9d9;
	border-radius: 6px;
	cursor: pointer;
	position: relative;
	overflow: hidden;
	transition: all 0.3s;
}

.avatar-uploader >>> .el-upload:hover {
	border-color: #409EFF;
}

.avatar-uploader-icon {
	font-size: 24px;
	color: #8c939d;
	width: 120px;
	height: 120px;
	line-height: 120px;
	text-align: center;
}

.avatar {
	width: 120px;
	height: 120px;
	display: block;
	object-fit: cover;
}

.upload-tip {
	font-size: 12px;
	color: #909399;
	margin-top: 8px;
	line-height: 1.5;
}

/* 按钮样式 */
.modern-dialog-footer {
	text-align: right;
	padding-top: 10px;
}

.btn-cancel {
	border-color: #dcdfe6;
	color: #606266;
}

.btn-cancel:hover {
	background: #f5f7fa;
	border-color: #c0c4cc;
	color: #606266;
}

.btn-submit {
	background: #409eff;
	border-color: #409eff;
	color: #ffffff;
}

.btn-submit:hover {
	background: #66b1ff;
	border-color: #66b1ff;
}

/* 滚动条样式 */
.fixed-dialog >>> .el-dialog__body::-webkit-scrollbar {
	width: 6px;
}

.fixed-dialog >>> .el-dialog__body::-webkit-scrollbar-track {
	background: #f5f5f5;
	border-radius: 3px;
}

.fixed-dialog >>> .el-dialog__body::-webkit-scrollbar-thumb {
	background: #c0c4cc;
	border-radius: 3px;
}

.fixed-dialog >>> .el-dialog__body::-webkit-scrollbar-thumb:hover {
	background: #909399;
}
